+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+function camelCase(key: string): string {
+  return key.replace(/-([a-zA-Z0-9])/g, (_, character: string) =>
+    character.toUpperCase()
+  );
+}
+
+function flatten(
+  value: Record<string, unknown>,
+  prefix = "",
+  output: Record<string, unknown> = {},
+): Record<string, unknown> {
+  for (const [key, item] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${camelCase(key)}` : camelCase(key);
+    if (
+      item !== null && typeof item === "object" && !Array.isArray(item)
+    ) {
+      flatten(item as Record<string, unknown>, name, output);
+    } else {
+      output[name] = item;
+    }
+  }
+  return output;
+}
+
+/** Parse Cliffy's simple rc format. */
+export function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const index = trimmed.indexOf("=");
+    if (index === -1) throw new Error(`Invalid RC entry "${line}".`);
+    const key = trimmed.slice(0, index).trim();
+    let value = trimmed.slice(index + 1).trim();
+    if (value.startsWith('"') && value.endsWith('"') && value.length >= 2) {
+      value = value.slice(1, -1);
+    }
+    values[camelCase(key)] = value === "true"
+      ? true
+      : value === "false"
+      ? false
+      : /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)
+      ? Number(value)
+      : value;
+  }
+  return values;
+}
+
+async function cwd(): Promise<string> {
+  // deno-lint-ignore no-explicit-any
+  const deno = (globalThis as any).Deno;
+  if (deno) return deno.cwd();
+  // dnt-shim-ignore
+  return (globalThis as any).process.cwd();
+}
+
+async function pathApi() {
+  // deno-lint-ignore no-explicit-any
+  const deno = (globalThis as any).Deno;
+  if (deno) {
+    const path = await import("@std/path");
+    return { join: path.join, resolve: path.resolve };
+  }
+  return await import("node:path");
+}
+
+async function readFile(path: string): Promise<string | undefined> {
+  try {
+    // deno-lint-ignore no-explicit-any
+    const deno = (globalThis as any).Deno;
+    if (deno) return await deno.readTextFile(path);
+    const fs = await import("node:fs/promises");
+    return await fs.readFile(path, "utf8");
+  } catch (error) {
+    if ((error as { code?: string }).code === "ENOENT") return undefined;
+    // Deno's NotFound error does not reliably expose a Node-style code.
+    if (error instanceof Error && error.name === "NotFound") return undefined;
+    throw error;
+  }
+}
+
+function fileName(name: string, format: string): string {
+  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
+}
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+/** Load and normalize a command configuration. */
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const paths = options.searchPaths ?? [await cwd()];
+  const formats = options.formats ?? [".json", ".rc"];
+  const path = await pathApi();
+  const found: Array<{ path: string; content: string; format: string }> = [];
+
+  for (const searchPath of paths) {
+    for (const format of formats) {
+      const filePath = path.resolve(path.join(searchPath, fileName(options.name, format)));
+      const content = await readFile(filePath);
+      if (typeof content !== "undefined") {
+        found.push({ path: filePath, content, format });
+        break;
+      }
+    }
+    if (found.length && !options.mergeConfigs) break;
+  }
+
+  const values: Record<string, unknown> = {};
+  // Apply in reverse: the earliest search path has highest precedence.
+  for (const config of found.slice().reverse()) {
+    try {
+      const parsed = options.parser
+        ? options.parser(config.content)
+        : config.format === ".json"
+        ? JSON.parse(config.content)
+        : parseRc(config.content);
+      if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
+        throw new Error("Configuration root must be an object.");
+      }
+      Object.assign(values, flatten(parsed));
+    } catch (error) {
+      throw new ConfigParseError(config.path, error);
+    }
+  }
+
+  return { path: found[0]?.path, values };
+}
